import{_ as b,$ as c,c as v,a as g,d as h,e as a,g as o,a2 as s,h as t,f as n,w as u,n as p,b as m,P as w}from"./index.2fed4629.js";import{g as y}from"./gameplayGauntlet.688d2006.js";const k={class:"help-container"},f={id:"top",class:"help-header"},_=["src"],x={id:"rewards",class:"help-section"},C={class:"crt-text-gold"},T={class:"help-footer"},B={__name:"gameplayGauntlet",setup(G){const d=c(),r=v(()=>d.query.autoScroll==="true");return(P,e)=>{const l=w,i=g("router-link");return m(),h("div",{class:p(["help-page",{"auto-scroll-mode":o(r)}])},[a("div",k,[a("header",f,[a("img",{src:o(y),alt:"Gameplay Gauntlet",class:"header-logo"},null,8,_),e[0]||(e[0]=a("div",{class:"header-text"},[a("h1",{class:"crt-text-gold"},"\u{1F3C6} GAMEPLAY GAUNTLET"),a("p",{class:"subtitle"},"Vote for the Next Game We Play!")],-1))]),e[6]||(e[6]=s('<section id="basics" class="help-section" data-v-b53b3e6a><h2 class="crt-text-gold" data-v-b53b3e6a>\u{1F4D6} How It Works</h2><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>Overview</h3><p data-v-b53b3e6a> Gameplay Gauntlet is a <strong data-v-b53b3e6a>community voting game</strong> where viewers decide which Steam game gets played next! A pool of ~1,500 games scrolls across the stream overlay \u2014 use your <strong data-v-b53b3e6a>vote budget</strong> to back your favorites. The first game to hit <strong data-v-b53b3e6a>11 votes</strong> after the 24-hour session timer expires is declared the <span class="highlight-gold" data-v-b53b3e6a>Community Pick</span> and gets played on stream! </p></div><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>\u{1F5F3}\uFE0F Voting Commands</h3><p data-v-b53b3e6a>Each game on the ticker has a unique <strong data-v-b53b3e6a>3-character code</strong> shown on its card. Use it to vote:</p><ul data-v-b53b3e6a><li data-v-b53b3e6a><code data-v-b53b3e6a>!rABC</code> \u2014 Place 1 vote on game with code <code data-v-b53b3e6a>ABC</code></li><li data-v-b53b3e6a><code data-v-b53b3e6a>!rABC 3</code> \u2014 Place 3 votes at once (up to 5 per game)</li><li data-v-b53b3e6a><code data-v-b53b3e6a>!r goTime</code> \u2014 Check your remaining vote budget &amp; cooldown status</li></ul></div></section><div class="pro-tip" data-v-b53b3e6a><strong data-v-b53b3e6a>\u{1F4A1} Strategy Tip:</strong> You can spread votes across multiple games or stack up to 5 on your top pick. Choose wisely \u2014 your budget is limited! </div><section id="budget" class="help-section" data-v-b53b3e6a><h2 class="crt-text-gold" data-v-b53b3e6a>\u{1F4B0} Vote Budget</h2><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>\u{1F4CA} Budget System</h3><ul data-v-b53b3e6a><li data-v-b53b3e6a><strong data-v-b53b3e6a>25 votes</strong> \u2014 Your total budget per session</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>5 max per game</strong> \u2014 Can&#39;t dump all votes on one game</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>+1 vote/hour</strong> \u2014 Budget replenishes hourly</li></ul><p data-v-b53b3e6a>Spend your votes wisely! Once you&#39;re out, you&#39;ll need to wait for the hourly replenish.</p></div><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>\u23F1\uFE0F Cooldowns</h3><ul data-v-b53b3e6a><li data-v-b53b3e6a><strong data-v-b53b3e6a>7\u201310 min</strong> \u2014 Personal cooldown between votes (randomized)</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>2 min</strong> \u2014 Per-game cooldown (can&#39;t pile onto the same game too fast)</li></ul></div><div class="warning-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>\u26A0\uFE0F Cooldown Penalty</h3><p data-v-b53b3e6a> Trying to vote during your cooldown <strong data-v-b53b3e6a>costs you a vote from your budget</strong> and <strong data-v-b53b3e6a>resets your cooldown</strong> to full! No votes are counted. Don&#39;t spam \u2014 be patient. </p></div><div class="warning-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>\u{1F4C9} Overdraft</h3><p data-v-b53b3e6a> If your budget hits zero (or goes negative), votes won&#39;t count and you won&#39;t earn rewards until the hourly replenish brings you back above zero. </p></div></section>',3)),a("section",x,[a("h2",C,[e[1]||(e[1]=t("\u{1F48E} Rewards & ",-1)),n(l,{currency:"zc",class:"points-inline"}),e[2]||(e[2]=t(" zCubes",-1))]),e[3]||(e[3]=a("div",{class:"content-block"},[a("h3",null,"\u{1F4B0} Reward Breakdown"),a("ul",null,[a("li",null,[a("strong",null,"+33 zC"),t(" \u2014 Per successful vote placed")])]),a("p",null,[t("Votes placed during cooldown or overdraft earn "),a("strong",null,"0 zC"),t(".")])],-1))]),e[7]||(e[7]=s('<section id="winning" class="help-section" data-v-b53b3e6a><h2 class="crt-text-gold" data-v-b53b3e6a>\u{1F3C6} Winning Conditions</h2><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>How a Winner Is Declared</h3><ol class="list-disc" data-v-b53b3e6a><li data-v-b53b3e6a>A <strong data-v-b53b3e6a>24-hour session timer</strong> counts down from when the gauntlet starts</li><li data-v-b53b3e6a>Once the timer expires, the leading game with <strong data-v-b53b3e6a>11+ votes</strong> is declared the winner</li><li data-v-b53b3e6a>A <span class="highlight-gold" data-v-b53b3e6a>winner banner</span> is automatically generated and posted to Discord</li><li data-v-b53b3e6a>The winning game gets played on the next stream!</li></ol></div><div class="pro-tip" data-v-b53b3e6a><strong data-v-b53b3e6a>\u{1F4A1} Note:</strong> If no game has reached 11 votes when the timer expires, voting continues until one does. The race isn&#39;t over until someone crosses the finish line! </div></section><section id="overlay" class="help-section" data-v-b53b3e6a><h2 class="crt-text-gold" data-v-b53b3e6a>\u{1F5A5}\uFE0F Reading the Overlay</h2><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>Ticker Bar</h3><p data-v-b53b3e6a>The bottom of the stream shows a scrolling ticker with game cards:</p><ul data-v-b53b3e6a><li data-v-b53b3e6a><strong data-v-b53b3e6a>Card size</strong> \u2014 Bigger cards = more votes (visual ranking)</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>3-char code</strong> \u2014 Shown on each card, use with <code data-v-b53b3e6a>!r</code></li><li data-v-b53b3e6a><strong data-v-b53b3e6a>Vote count</strong> \u2014 Current tally displayed on each card</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>Voter avatars</strong> \u2014 Circular Twitch avatars of who voted, with cooldown ring timers</li><li data-v-b53b3e6a><strong data-v-b53b3e6a>\u{1F3C6} separator</strong> \u2014 Shows session time remaining and <code data-v-b53b3e6a>!r goTime</code> hint</li></ul></div><div class="content-block" data-v-b53b3e6a><h3 data-v-b53b3e6a>Masonry Grid</h3><p data-v-b53b3e6a>Above the ticker, a large grid displays all ~1,500 eligible games with Steam artwork. Games with votes are highlighted and promoted to the ticker.</p></div></section>',2)),a("footer",T,[n(i,{to:"/help",class:"back-link"},{default:u(()=>[...e[4]||(e[4]=[t("\u2190 Back to Help Center",-1)])]),_:1}),e[5]||(e[5]=a("p",{class:"crt-text-cyan"},"Need more help? Ask in Twitch chat!",-1))])])],2)}}},V=b(B,[["__scopeId","data-v-b53b3e6a"]]);export{V as default};
